def _check_high_complexity(
    self, 
    tree: ast.AST, 
    file_path: str, 
    lines: List[str]
) -> List[CodeIssue]:
    """检测圈复杂度过高的函数"""
    issues = []

    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            complexity = self._calculate_complexity(node)

            if complexity > self.max_complexity:
                severity = IssueSeverity.HIGH if complexity > self.max_complexity * 2 else IssueSeverity.MEDIUM

                issues.append(CodeIssue(
                    file_path=file_path,
                    issue_type=IssueType.HIGH_COMPLEXITY,
                    severity=severity,
                    line_number=node.lineno,
                    description=f"函数 '{node.name}' 圈复杂度过高，为 {complexity}（建议不超过 {self.max_complexity}）",
                    suggestion="简化条件逻辑，使用策略模式或状态模式替代复杂的条件判断。",
                    code_snippet=self._get_code_snippet(lines, node.lineno, min(node.lineno + 3, len(lines))),
                ))

    return issues

def _calculate_complexity(self, node: ast.AST) -> int:
    """计算圈复杂度"""
    complexity = 1  # 基础复杂度

    for child in ast.walk(node):
        if isinstance(child, (ast.If, ast.While, ast.For, ast.AsyncFor)):
            complexity += 1
        elif isinstance(child, ast.ExceptHandler):
            complexity += 1
        elif isinstance(child, ast.BoolOp):
            complexity += len(child.values) - 1

    return complexity

def _check_deep_nesting(
    self,
    tree: ast.AST,
    file_path: str,
    lines: List[str]
) -> List[CodeIssue]:
    """检测过深的嵌套"""
    issues = []

    for node in ast.walk(tree):
        if isinstance(node, (ast.If, ast.While, ast.For, ast.AsyncFor, ast.With, ast.Try)):
            depth = self._calculate_nesting_depth(node)

            if depth > self.max_nesting_depth:
                issues.append(CodeIssue(
                    file_path=file_path,
                    issue_type=IssueType.DEEP_NESTING,
                    severity=IssueSeverity.MEDIUM,
                    line_number=node.lineno,
                    description=f"代码嵌套过深，深度为 {depth}（建议不超过 {self.max_nesting_depth}）",
                    suggestion="使用卫语句（guard clauses）提前返回，或提取嵌套代码到独立函数。",
                    code_snippet=self._get_code_snippet(lines, node.lineno, min(node.lineno + 3, len(lines))),
                ))

    return issues

def _calculate_nesting_depth(self, node: ast.AST) -> int:
    """计算节点的嵌套深度"""
    depth = 0
    parent = ast.walk(node)
    for _ in parent:
        if isinstance(node, (ast.If, ast.While, ast.For, ast.AsyncFor, ast.With, ast.Try)):
            depth += 1
    return depth

def _get_code_snippet(self, lines: List[str], start: int, end: int) -> str:
    """获取代码片段"""
    snippet_lines = lines[start-1:end]
    return '\n'.join(snippet_lines)
